int main() {
    int pipefd[2];
    pid_t childpid;

    // Step 1: Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Step 2: Fork a child process
    childpid = fork();
    if (childpid == -1) {
        perror("fork");
        return 1;
    } else if (childpid == 0) {
        // This is the child process
        // Step 3: Close the write end of the pipe
        close(pipefd[1]);

        // Step 4: Duplicate the file descriptor
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Step 5: Close the pipe file descriptor
        close(pipefd[0]);

        // Step 6: Execute the process (for example, a shell)
        execlp("/bin/sh", "sh", NULL);
        perror("execlp");
        _exit(1);
    } else {
        // This is the parent process
        // Step 7: Close the read end of the pipe
        close(pipefd[0]);

        // Step 8: Write to the pipe
        const char *message = "Hello from the parent process!";
        write(pipefd[1], message, strlen(message));

        // Step 9: Close the write end of the pipe
        close(pipefd[1]);

        // Step 10: Wait for the child to finish
        wait(NULL);
    }

    return 0;
}
```

In this code, the child process opens the pipe's read end as both the standard input and standard output, effectively connecting the parent's output to the child's input. The parent then writes a message to the pipe, which the child reads.

